queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasAwards ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Awards } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?awardname ?categoryname WHERE {
  ?awards_categories a :Awards_Categories .
  ?categories a :Categories .
  ?awards_categories p:hasCategories ?categories .
  ?awards a :Awards .
  ?awards_categories p:hasAwards ?awards .
  ?awards p:awardName ?awardname .
  ?categories p:categoryName ?categoryname .
} }
  collective: { SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasAwards ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Awards } }
  FILTER(?nf = ?total)
} }
}
